// Extraer datos del webhook
const message = $input.first().json.body.message;
const sessionId = $input.first().json.body.sessionId || 'new-session';
const timestamp = $input.first().json.body.timestamp;

// Obtener el knowledge base del nodo anterior
const knowledgeBase = $('Load Knowledge Base').first().json;

// Construir contexto para DeepSeek
const context = `
Eres un asistente inteligente de Eskadia.ai, una plataforma de automatización empresarial.

INFORMACIÓN DE ESKADIA:

## CRM - Eskadia Core
${JSON.stringify(knowledgeBase.crm, null, 2)}

## Servicios - Eskadia Flow
${JSON.stringify(knowledgeBase.services, null, 2)}

## Academia - Eskadia Academy
${JSON.stringify(knowledgeBase.academy, null, 2)}

## Precios
${JSON.stringify(knowledgeBase.pricing, null, 2)}

## FAQs
${JSON.stringify(knowledgeBase.faqs, null, 2)}

INSTRUCCIONES:
1. Responde en español de forma amigable y profesional
2. Usa emojis ocasionalmente para hacer la conversación más cálida
3. Si la pregunta está relacionada con la información anterior, úsala para responder
4. Si mencionas características específicas, cita las fuentes relevantes
5. Mantén las respuestas concisas pero informativas (máximo 200 palabras)
6. Si no sabes algo, sé honesto y sugiere contactar al equipo
7. Enfatiza los beneficios únicos: IA integrada, automatización nativa, modelo freemium
`;

return {
  json: {
    message,
    sessionId,
    timestamp,
    context,
    knowledgeBase
  }
};

// Obtener la respuesta de DeepSeek
const aiResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || 'Lo siento, no pude generar una respuesta.';

// Obtener el knowledge base
const knowledgeBase = $('Prepare Context').first().json.knowledgeBase;
const sessionId = $('Prepare Context').first().json.sessionId;

// Función para detectar menciones de temas y extraer fuentes
function extractSources(response, kb) {
  const sources = [];
  const responseLower = response.toLowerCase();

  // Detectar menciones del CRM
  if (responseLower.includes('crm') || responseLower.includes('eskadia core') || 
      responseLower.includes('apollo') || responseLower.includes('enriquecimiento')) {
    sources.push({
      title: 'Eskadia Core - CRM Inteligente',
      url: 'https://eskadia.ai/crm'
    });
  }

  // Detectar menciones de Flow
  if (responseLower.includes('flow') || responseLower.includes('consultoría') || 
      responseLower.includes('automatización a medida') || responseLower.includes('implementación')) {
    sources.push({
      title: 'Eskadia Flow - Automatización a Medida',
      url: 'https://eskadia.ai/flow'
    });
  }

  // Detectar menciones de Academy
  if (responseLower.includes('academy') || responseLower.includes('cursos') || 
      responseLower.includes('formación') || responseLower.includes('certificación') ||
      responseLower.includes('aprender')) {
    sources.push({
      title: 'Eskadia Academy - Cursos y Certificaciones',
      url: 'https://eskadia.ai/academy'
    });
  }

  // Detectar menciones de precios
  if (responseLower.includes('precio') || responseLower.includes('plan') || 
      responseLower.includes('$') || responseLower.includes('gratis') ||
      responseLower.includes('free') || responseLower.includes('pro') ||
      responseLower.includes('enterprise')) {
    sources.push({
      title: 'Planes y Precios de Eskadia',
      url: 'https://eskadia.ai/pricing'
    });
  }

  // Detectar menciones de características específicas
  if (responseLower.includes('n8n')) {
    sources.push({
      title: 'Integración con n8n',
      url: 'https://eskadia.ai/crm#features'
    });
  }

  // Eliminar duplicados
  const uniqueSources = sources.filter((source, index, self) =>
    index === self.findIndex((s) => s.url === source.url)
  );

  return uniqueSources;
}

// Extraer fuentes relevantes
const sources = extractSources(aiResponse, knowledgeBase);

// Construir respuesta final
return {
  json: {
    response: aiResponse,
    sources: sources.slice(0, 3), // Máximo 3 fuentes
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    metadata: {
      model: 'deepseek-chat',
      tokensUsed: $input.first().json.usage?.total_tokens || 0
    }
  }
};

// Manejo de errores
const error = $input.first().json.error || 'Error desconocido';

return {
  json: {
    response: 'Lo siento, hubo un problema al procesar tu mensaje. Por favor, intenta de nuevo o contacta con nuestro equipo de soporte.',
    sources: [
      {
        title: 'Contacto Eskadia',
        url: 'https://eskadia.ai/contact'
      }
    ],
    sessionId: $('Prepare Context').first()?.json?.sessionId || 'error-session',
    error: true,
    errorDetails: error
  }
};
